576	    #[track_caller]
577	    pub fn assert_markdown_suggestion_result(text: &str, mut linter: impl Linter, needle: &str) {
578	        if !search_for_suggestion(DocumentType::Markdown, text, &mut linter, needle, 0) {
579	            panic!("No suggestion sequence produced the expected result.\nExpected: {needle}");
580	        }
581	    }
582	
583	    /// Recursively searches all suggestion combinations using depth-first search.
584	    /// Returns true if any path reaches the expected result, false otherwise.
585	    fn search_for_suggestion(
586	        doc_type: DocumentType,
587	        text: &str,
588	        linter: &mut impl Linter,
589	        needle: &str,
590	        depth: usize,
591	    ) -> bool {
592	        // Prevent infinite recursion (e.g. cycles in suggestions)
593	        if depth > 100 {
594	            eprintln!("⚠️  Reached depth limit (100)");
595	            return false;
596	        }
597	
598	        // Check if we've reached the expected result
599	        if text == needle {
600	            return true;
601	        }
602	
603	        // Lint current text and try each suggestion branch
604	        let chars: Vec<char> = text.chars().collect();
605	        let document = create_document(&chars, doc_type);
606	        let lints = linter.lint(&document);
607	
608	        if let Some(lint) = lints.first() {
609	            for sug in lint.suggestions.iter() {
610	                let mut chars_copy = chars.clone();
611	                sug.apply(lint.span, &mut chars_copy);
612	                let next: String = chars_copy.iter().collect();
613	
614	                // Recursively search this branch
615	                if search_for_suggestion(doc_type, &next, linter, needle, depth + 1) {
616	                    return true;
617	                }
618	            }
619	        }
620	
621	        false
622	    }
