366	/// A struct for collecting the output of a number of individual [Linter]s.
367	/// Each child can be toggled via the public, mutable `Self::config` object.
368	pub struct LintGroup {
369	    pub config: LintGroupConfig,
370	    /// We use a binary map here so the ordering is stable.
371	    linters: BTreeMap<String, Box<dyn Linter>>,
372	    /// We use a binary map here so the ordering is stable.
373	    chunk_expr_linters: BTreeMap<String, Box<dyn ExprLinter<Unit = Chunk>>>,
374	    /// Since [`ExprLinter`]s operate on a chunk-basis, we can store a
375	    /// mapping of `Chunk -> Lint` and only re-run the expr linters
376	    /// when a chunk changes.
377	    ///
378	    /// Since the expr linter results also depend on the config, we hash it and pass it as part
379	    /// of the key.
380	    chunk_expr_cache: LruCache<(CharString, u64), BTreeMap<String, Vec<Lint>>>,
381	    hasher_builder: RandomState,
382	    clashing_linter_names: Option<Vec<String>>,
383	}
384	
385	impl LintGroup {
386	    // Constructor methods
387	
388	    pub fn empty() -> Self {
389	        Self {
390	            config: LintGroupConfig::default(),
391	            linters: BTreeMap::new(),
392	            chunk_expr_linters: BTreeMap::new(),
393	            chunk_expr_cache: LruCache::new(NonZero::new(1000).unwrap()),
394	            hasher_builder: RandomState::default(),
395	            clashing_linter_names: None,
396	        }
397	    }
398	
399	    // Non-constructor methods
400	
401	    /// Check if the group already contains a linter with a given name.
402	    pub fn contains_key(&self, name: impl AsRef<str>) -> bool {
403	        self.linters.contains_key(name.as_ref())
404	            || self.chunk_expr_linters.contains_key(name.as_ref())
405	    }
406	
407	    /// Add a [`Linter`] to the group, returning whether the operation was successful.
408	    /// If it returns `false`, it is because a linter with that key already existed in the group.
409	    pub fn add(&mut self, name: impl AsRef<str>, linter: impl Linter + 'static) -> bool {
410	        if self.contains_key(&name) {
411	            if self.clashing_linter_names.is_none() {
412	                self.clashing_linter_names = Some(vec![name.as_ref().to_string()]);
413	            } else if let Some(clashing_names) = &mut self.clashing_linter_names {
414	                clashing_names.push(name.as_ref().to_string());
415	            }
416	            false
417	        } else {
418	            self.linters
419	                .insert(name.as_ref().to_string(), Box::new(linter));
420	            true
421	        }
422	    }
423	
424	    /// Add a chunk-based [`ExprLinter`] to the group, returning whether the operation was successful.
425	    /// If it returns `false`, it is because a linter with that key already existed in the group.
426	    ///
427	    /// This function is not significantly different from [`Self::add`], but allows us to take
428	    /// advantage of some properties of chunk-based [`ExprLinter`]s for cache optimization.
429	    pub fn add_chunk_expr_linter(
430	        &mut self,
431	        name: impl AsRef<str>,
432	        // linter: impl ExprLinter + 'static,
433	        linter: impl ExprLinter<Unit = Chunk> + 'static,
434	    ) -> bool {
435	        if self.contains_key(&name) {
436	            if self.clashing_linter_names.is_none() {
437	                self.clashing_linter_names = Some(vec![name.as_ref().to_string()]);
438	            } else if let Some(clashing_names) = &mut self.clashing_linter_names {
439	                clashing_names.push(name.as_ref().to_string());
440	            }
441	            false
442	        } else {
443	            self.chunk_expr_linters
444	                .insert(name.as_ref().to_string(), Box::new(linter) as _);
445	            true
446	        }
447	    }
448	
449	    /// Merge the contents of another [`LintGroup`] into this one.
450	    /// The other lint group will be left empty after this operation.
451	    pub fn merge_from(&mut self, other: &mut LintGroup) {
452	        self.config.merge_from(&mut other.config);
453	
454	        let other_linters = std::mem::take(&mut other.linters);
455	        if let Some((conflicting_key, _)) = other_linters.iter().find(|(k, _)| self.contains_key(k))
456	        {
457	            if self.clashing_linter_names.is_none() {
458	                self.clashing_linter_names = Some(vec![conflicting_key.clone()]);
459	            } else if let Some(clashing_names) = &mut self.clashing_linter_names {
460	                clashing_names.push(conflicting_key.clone());
461	            }
462	        }
463	        self.linters.extend(other_linters);
464	
465	        let other_expr_linters = std::mem::take(&mut other.chunk_expr_linters);
466	        if let Some((conflicting_key, _)) = other_expr_linters
467	            .iter()
468	            .find(|(k, _)| self.contains_key(k))
469	        {
470	            if self.clashing_linter_names.is_none() {
471	                self.clashing_linter_names = Some(vec![conflicting_key.clone()]);
472	            } else if let Some(clashing_names) = &mut self.clashing_linter_names {
473	                clashing_names.push(conflicting_key.clone());
474	            }
475	        }
476	        self.chunk_expr_linters.extend(other_expr_linters);
477	    }
478	
479	    pub fn iter_keys(&self) -> impl Iterator<Item = &str> {
480	        self.linters
481	            .keys()
482	            .chain(self.chunk_expr_linters.keys())
483	            .map(|v| v.as_str())
484	    }
