486	    /// Set all contained rules to a specific value.
487	    /// Passing `None` will unset that rule, allowing it to assume its default state.
488	    pub fn set_all_rules_to(&mut self, enabled: Option<bool>) {
489	        let keys = self.iter_keys().map(|v| v.to_string()).collect::<Vec<_>>();
490	
491	        for key in keys {
492	            match enabled {
493	                Some(v) => self.config.set_rule_enabled(key, v),
494	                None => self.config.unset_rule_enabled(key),
495	            }
496	        }
497	    }
