534	        /// Add a `Linter` to the group, setting it to be enabled or disabled.
535	        macro_rules! insert_struct_rule {
536	            ($rule:ident, $default_config:expr) => {
537	                out.add(stringify!($rule), $rule::default());
538	                out.config
539	                    .set_rule_enabled(stringify!($rule), $default_config);
