862	    pub fn organized_lints(&mut self, document: &Document) -> BTreeMap<String, Vec<Lint>> {
863	        let mut results = BTreeMap::new();
864	
865	        // Normal linters
866	        for (key, linter) in &mut self.linters {
867	            if self.config.is_rule_enabled(key) {
868	                results.insert(key.clone(), linter.lint(document));
869	            }
870	        }
871	
872	        // Expr linters
873	        for chunk in document.iter_chunks() {
874	            let Some(chunk_span) = chunk.span() else {
875	                continue;
876	            };
877	
878	            let chunk_chars = document.get_span_content(&chunk_span);
879	            let config_hash = self.hasher_builder.hash_one(&self.config);
880	            let cache_key = (chunk_chars.into(), config_hash);
881	
882	            let mut chunk_results = if let Some(hit) = self.chunk_expr_cache.get(&cache_key) {
883	                hit.clone()
884	            } else {
885	                let mut pattern_lints = BTreeMap::new();
886	
887	                for (key, linter) in &mut self.chunk_expr_linters {
888	                    if self.config.is_rule_enabled(key) {
889	                        let lints =
890	                            run_on_chunk(linter, chunk, document.get_source()).map(|mut l| {
891	                                l.span.pull_by(chunk_span.start);
892	                                l
893	                            });
894	
895	                        pattern_lints.insert(key.clone(), lints.collect());
896	                    }
897	                }
898	
899	                self.chunk_expr_cache.put(cache_key, pattern_lints.clone());
900	                pattern_lints
901	            };
902	
903	            // Bring the spans back into document-space
904	            for value in chunk_results.values_mut() {
905	                for lint in value {
906	                    lint.span.push_by(chunk_span.start);
907	                }
908	            }
909	
910	            for (key, mut vec) in chunk_results {
911	                results.entry(key).or_default().append(&mut vec);
912	            }
913	        }
914	
915	        results
916	    }
917	}
