662	            SequenceExpr::default().then_kind_both(TokenKind::is_noun, TokenKind::is_verb);
663	        let doc = Document::new_plain_english_curated("Use a good example.");
664	        let matches = noun_and_verb.iter_matches_in_doc(&doc).collect::<Vec<_>>();
