fn is_followed_by_nominal(word: &Token, context: Option<(&[Token], &[Token])>, src: &[char]) -> bool {
    if let Some((_, after)) = context {
        // Skip whitespace and look for a determiner or noun
        for tok in after {
            if tok.kind.is_whitespace() {
                continue;
            }
            return tok.kind.is_nominal()
                || tok.kind.is_noun()
                || tok.kind.is_pronoun()
                || tok.kind.is_proper_noun()
                || tok.kind.is_determiner();
        }
    }
    false
}

fn is_verb_preceded_by_verb_helper(word: &Token, context: Option<(&[Token], &[Token])>, _src: &[char]) -> bool {
    if let Some((before, _)) = context {
        // Check tokens before the word (reversed order through the context)
        if !before.is_empty() {
            // Look at last few tokens before the match
            let mut skip_ws = true;
            for tok in before.iter().rev() {
                if tok.kind.is_whitespace() {
                    skip_ws = false;
                    continue;
                }
                if skip_ws {
                    continue;
                }
                // Check if preceded by: auxiliary verb, "to", "will", "can", modal
                return tok.kind.is_auxiliary_verb()
                    || tok.kind.is_linking_verb()
                    || tok.kind.is_verb()
                    || tok.kind.is_modal_verb()
                    || tok.kind.is_verb_lemma();
