#[cfg(test)]
mod tests {
    use super::VerseAsVerb;
    use crate::linting::tests::{assert_lint_count, assert_suggestion_result};

    // Test that "verse" used as a noun is NOT flagged
    #[test]
    fn does_not_flag_verse_as_noun() {
        assert_lint_count(
            "This verse of poetry is my favorite.",
            VerseAsVerb::default(),
            0,
        );
    }

    // Test that "verse" used as a noun with article is NOT flagged
    #[test]
    fn does_not_flag_a_verse() {
        assert_lint_count(
            "He wrote a verse about nature.",
            VerseAsVerb::default(),
            0,
        );
    }

    // Test that "versed" in "well versed" is NOT flagged
    #[test]
    fn does_not_flag_well_versed() {
        assert_lint_count(
            "She is well versed in literature.",
            VerseAsVerb::default(),
            0,
        );
    }

    // Test that "versed" in "well-versed" is NOT flagged
    #[test]
    fn does_not_flag_well_versed_hyphen() {
        assert_lint_count(
            "She is well-versed in literature.",
            VerseAsVerb::default(),
            0,
        );
    }

    // Test that "verses" used as a plural noun is NOT flagged
    #[test]
    fn does_not_flag_verses_as_noun() {
        assert_lint_count(
            "Those verses are from the Bible.",
            VerseAsVerb::default(),
            0,
        );
    }

    // Test flagging "verse" as a verb
    #[test]
    fn flags_verse_as_verb() {
        assert_suggestion_result(
            "I will verse you in the game.",
            VerseAsVerb::default(),
            "I will face you in the game.",
        );
    }

    // Test flagging "versed" as a verb
    #[test]
    fn flags_versed_as_verb() {
        assert_suggestion_result(
            "I versed him yesterday in chess.",
            VerseAsVerb::default(),
            "I faced him yesterday in chess.",
        );
    }

    // Test flagging "verses" as a verb
    #[test]
    fn flags_verses_as_verb() {
        assert_suggestion_result(
            "The bot verses other bots in the game.",
            VerseAsVerb::default(),
            "The bot faces other bots in the game.",
        );
    }

    // Test flagging "versing" as a verb
    #[test]
    fn flags_versing() {
        assert_suggestion_result(
            "I am versing the computer in this game.",
            VerseAsVerb::default(),
            "I am facing the computer in this game.",
        );
    }

    // Test "verse" preceded by "to"
    #[test]
    fn flags_verse_after_to() {
        assert_suggestion_result(
            "you can verse the bot online.",
            VerseAsVerb::default(),
            "you can face the bot online.",
        );
    }

    // Test that "verse" after "a" is NOT flagged
    #[test]
    fn does_not_flag_verse_after_article() {
        assert_lint_count(
            "In the first verse of the song, she sings about love.",
            VerseAsVerb::default(),
            0,
        );
    }
}

