use crate::expr::{Expr, SequenceExpr};
use crate::linting::expr_linter::{Chunk, preceded_by_word};
use crate::linting::{ExprLinter, Lint, LintKind, Suggestion};
use crate::patterns::WordSet;
use crate::{CharStringExt, Token, TokenKind};

/// Linter that flags "verse" used as a verb (meaning "to compete against" or "versus").
///
/// The English word "versus" is a preposition, but some speakers treat it as a verb:
/// "I versed him" instead of "I played against him".
/// This linter catches the verbal inflections: verse, verses, versed, versing.
pub struct VerseAsVerb {
    expr: SequenceExpr,
}

impl Default for VerseAsVerb {
    fn default() -> Self {
        Self {
            expr: SequenceExpr::with(WordSet::new(&["verse", "verses", "versed", "versing"])),
        }
    }
}

impl ExprLinter for VerseAsVerb {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint_with_context(
        &self,
        matched_tokens: &[Token],
        source: &[char],
        context: Option<(&[Token], &[Token])>,
    ) -> Option<Lint> {
        let word = matched_tokens.first()?;
        let word_content = word.span.get_content(source);

        // Determine which inflected form we're dealing with
        let lower: String = word_content.iter().map(|c| c.to_ascii_lowercase()).collect();
        let form = lower.as_str();

        // "versing" — always flag it (it's archaic/nonstandard English)
        if form == "versing" {
            return build_lint(word, source, "versing");
        }

        // For "verse" (the lemma) and "verses" (3rd person singular present):
        // Check if used as a verb by looking at preceding context
        if form == "verse" || form == "verses" {
            // If preceded by a determiner/article/possessive/quantifier -> likely a noun
            if preceded_by_word(context, |tok| {
                tok.kind.is_determiner()
                    || tok.kind.is_adjective()
                    || tok.kind.is_possessive_determiner()
                    || tok.kind.is_possessive_nominal()
                    || tok.kind.is_number()
            }) {
                return None;
            }

            // If preceded by article or quantifier word (like "the", "a", "this", "that", "each", "every")
            // check word content
            if preceded_by_word(context, |tok| {
                tok.kind.is_word()
            }) {
                // Get the actual word text
                if let Some((before, _)) = context {
                    for tok in before.iter().rev() {
                        if tok.kind.is_whitespace() {
                            continue;
                        }
                        if tok.kind.is_word() {
                            let preceding = tok.span.get_content(source);
                            let prev_lower: String = preceding.iter().map(|c| c.to_ascii_lowercase()).collect();
                            // If preceded by a determiner/article/possessive, it's a noun
                            if matches!(
                                prev_lower.as_str(),
                                "the" | "a" | "an" | "this" | "that" | "these" | "those"
                                    | "my" | "your" | "his" | "her" | "its" | "our" | "their"
                                    | "each" | "every" | "one" | "some" | "any" | "no"
                            ) {
                                return None;
                            }
                            // If preceded by "of" it's probably part of a prepositional phrase (noun)
                            if prev_lower.as_str() == "of" {
                                return None;
                            }
                            // If preceded by an adjective like "first", "last", "next", "beautiful"
                            if tok.kind.is_adjective() {
                                return None;
                            }
                        }
                        break;
                    }
                }
            }
        }

        // For "versed": don't flag if part of "well-versed" or preceded by "be" verb
        if form == "versed" {
            if preceded_by_word(context, |tok| {
                let is_well = tok.kind.is_word()
                    && tok.span.get_content(source).eq_ignore_ascii_case_chars(&['w', 'e', 'l', 'l']);
                is_well
                    || tok.kind.is_linking_verb()
                    || tok.kind.is_adverb()
                    || tok.kind.is_adjective()
            }) {
                return None;
            }

            // Also check for "well-versed" with hyphen
            // The token before "versed" is a hyphen, and the token before that is "well"
            if let Some((before, _)) = context {
                if before.len() >= 2 {
                    let second_last = &before[before.len() - 1];
                    let third_last = &before[before.len() - 2];
                    if second_last.kind.is_hyphen()
                        && third_last.kind.is_word()
                        && third_last.span.get_content(source).eq_ignore_ascii_case_chars(&['w', 'e', 'l', 'l'])
                    {
                        return None;
                    }
                }
            }
        }

        // Don't flag if the word is being used in a clearly nominal context
        // (preceded by a possessive like "poem's")
        if preceded_by_word(context, |tok| {
            tok.kind.is_possessive_nominal() || tok.kind.is_possessive_noun()
        }) {
            return None;
        }

        // If the word itself is tagged as definitely a noun but not a verb
        if let TokenKind::Word(Some(meta)) = &word.kind {
            if meta.is_noun() && !meta.is_verb() {
                return None;
            }
        }

        build_lint(word, source, form)
    }

    fn description(&self) -> &str {
        "Flags 'verse', 'verses', 'versed', and 'versing' when used as verbs meaning 'to compete against'."
    }
}

fn build_lint(word: &Token, source: &[char], form: &str) -> Option<Lint> {
    let message = match form {
        "verse" => "'Verse' should not be used as a verb. Consider using 'face', 'play against', or 'compete against' instead.",
        "verses" => "'Verses' should not be used as a verb. Consider using 'faces', 'plays against', or 'competes against' instead.",
        "versed" => "'Versed' should not be used as a verb (simple past). Consider using 'faced', 'played against', or 'competed against' instead.",
        "versing" => "'Versing' is not standard English. Consider using 'facing', 'playing against', or 'competing against' instead.",
        _ => return None,
    };

    let suggestion_word = match form {
        "verse" => "face",
        "verses" => "faces",
        "versed" => "faced",
        "versing" => "facing",
        _ => return None,
    };

    Some(Lint {
        span: word.span,
        lint_kind: LintKind::WordChoice,
        suggestions: vec![Suggestion::replace_with_match_case(
            suggestion_word.chars().collect(),
            word.span.get_content(source),
        )],
        message: message.to_owned(),
        priority: 63,
    })
}

